const express = require('express');
const bodyParser = require('body-parser');
const crypto = require('crypto');

const app = express();
app.use(bodyParser.json());

// In-memory database to store level completion data and rewards
let levelData = {};
let rewards = {
  'level1': { points: 50, timeBonus: 20 },
  'level2': { points: 100, timeBonus: 30 },
  'level3': { points: 150, timeBonus: 40 }
};

// Middleware to validate client-reported metrics
function validateMetrics(req, res, next) {
  const { level, score, time } = req.body;
  if (!level || !score || !time) {
    return res.status(400).json({ error: 'Missing required fields' });
  }
  if (isNaN(score) || isNaN(time)) {
    return res.status(400).json({ error: 'Score and time must be numbers' });
  }
  next();
}

// Endpoint to complete a level
app.post('/complete-level', validateMetrics, (req, res) => {
  const { level, score, time } = req.body;
  if (!levelData[level]) {
    levelData[level] = [];
  }
  levelData[level].push({ score, time });

  // Award rewards based on client-reported metrics
  let totalScore = score + (timeBonus ? timeBonus : 0);
  const reward = rewards[level];
  if (reward) {
    totalScore += reward.points;
    if (time <= reward.timeBonus) {
      totalScore += reward.timeBonus;
    }
  }

  res.json({ message: 'Level completed successfully', totalScore });
});

// Endpoint to claim rewards
app.post('/claim-rewards', validateMetrics, (req, res) => {
  const { level, score, time } = req.body;
  if (!levelData[level] || !levelData[level].length) {
    return res.status(400).json({ error: 'No level completion data found' });
  }

  // Award rewards based on client-reported metrics
  let totalScore = score + (timeBonus ? timeBonus : 0);
  const reward = rewards[level];
  if (reward) {
    totalScore += reward.points;
    if (time <= reward.timeBonus) {
      totalScore += reward.timeBonus;
    }
  }

  res.json({ message: 'Rewards claimed successfully', totalScore });
});

// Middleware to authenticate requests
function authenticateRequest(req, res, next) {
  const authHeader = req.headers['authorization'];
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  const token = authHeader.split(' ')[1];
  // Validate token (e.g., check signature, expiration)
  if (token !== process.env.API_TOKEN) {
    return res.status(401).json({ error: 'Invalid token' });
  }
  next();
}

// Apply authentication middleware to all routes
app.use(authenticateRequest);

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});